# use_google_benchmark_template ----
## setup ----
# This file uses temporary package directories to validate that
# `use_google_benchmark_template()` creates benchmark files and appends CMake
# entries correctly for both simple and fixture modes.

## IO correctness ----
test_that("`use_google_benchmark_template()` works with correct inputs", {
  temp_path <- file.path(tempdir(), "rcmdcheckgooglebenchmarksimple")
  benchmark_name <- "FIMSMath_ClassName_FunctionName"
  dir.create(temp_path, showWarnings = FALSE)
  on.exit(unlink(temp_path, recursive = TRUE, force = TRUE), add = TRUE)

  withr::with_dir(
    new = temp_path,
    code = {
      suppressMessages(invisible(capture.output(usethis::create_package(temp_path))))
      suppressMessages(usethis::proj_set(temp_path))
      suppressMessages(usethis::use_directory(file.path("tests", "google_benchmark")))
      file.create(file.path("tests", "google_benchmark", "CMakeLists.txt"))

      suppressMessages(FIMS:::use_google_benchmark_template(
        name = benchmark_name
      ))

      generated_path <- file.path(
        temp_path, "tests", "google_benchmark",
        paste0("benchmark_", benchmark_name, ".cpp")
      )
      generated_lines <- readLines(generated_path)
      cmake_lines <- readLines(file.path(temp_path, "tests", "google_benchmark", "CMakeLists.txt"))

      #' @description Test that simple mode writes the expected benchmark file.
      expect_true(file.exists(generated_path))
      #' @description Test that simple mode includes the Google Benchmark header.
      expect_true(any(grepl("#include \"benchmark/benchmark.h\"", generated_lines, fixed = TRUE)))
      #' @description Test that simple mode does not include gtest headers.
      expect_false(any(grepl("#include \"gtest/gtest.h\"", generated_lines, fixed = TRUE)))
      #' @description Test that benchmark symbol naming uses ClassName_FunctionName.
      expect_true(any(grepl("BM_ClassName_FunctionName", generated_lines, fixed = TRUE)))
      #' @description Test that simple mode does not link GTest in CMake.
      expect_false(any(grepl("GTest::gtest", cmake_lines, fixed = TRUE)))
    }
  )
})

## Edge handling ----
test_that("`use_google_benchmark_template()` supports fixture template", {
  temp_path <- file.path(tempdir(), "rcmdcheckgooglebenchmarkfixture")
  benchmark_name <- "FIMSMath_ClassName_FunctionName"
  dir.create(temp_path, showWarnings = FALSE)
  on.exit(unlink(temp_path, recursive = TRUE, force = TRUE), add = TRUE)

  withr::with_dir(
    new = temp_path,
    code = {
      suppressMessages(invisible(capture.output(usethis::create_package(temp_path))))
      suppressMessages(usethis::proj_set(temp_path))
      suppressMessages(usethis::use_directory(file.path("tests", "google_benchmark")))
      file.create(file.path("tests", "google_benchmark", "CMakeLists.txt"))

      suppressMessages(FIMS:::use_google_benchmark_template(
        name = benchmark_name,
        type = "fixture"
      ))

      generated_path <- file.path(
        temp_path, "tests", "google_benchmark",
        paste0("benchmark_", benchmark_name, ".cpp")
      )
      generated_lines <- readLines(generated_path)
      cmake_lines <- readLines(file.path(temp_path, "tests", "google_benchmark", "CMakeLists.txt"))

      #' @description Test that fixture mode writes the expected benchmark file.
      expect_true(file.exists(generated_path))
      #' @description Test that fixture mode includes gtest headers.
      expect_true(any(grepl("#include \"gtest/gtest.h\"", generated_lines, fixed = TRUE)))
      #' @description Test that fixture mode includes the fixture scaffold.
      expect_true(any(grepl("struct BenchFixture", generated_lines, fixed = TRUE)))
      #' @description Test that benchmark symbol naming uses ClassName_FunctionName.
      expect_true(any(grepl("BM_ClassName_FunctionName", generated_lines, fixed = TRUE)))
      #' @description Test that fixture mode links GTest in CMake.
      expect_true(any(grepl("GTest::gtest", cmake_lines, fixed = TRUE)))
    }
  )
})

## Error handling ----
test_that("`use_google_benchmark_template()` returns correct error messages", {
  temp_path <- file.path(tempdir(), "rcmdcheckgooglebenchmarknameformat")
  dir.create(temp_path, showWarnings = FALSE)
  on.exit(unlink(temp_path, recursive = TRUE, force = TRUE), add = TRUE)

  withr::with_dir(
    new = temp_path,
    code = {
      suppressMessages(invisible(capture.output(usethis::create_package(temp_path))))
      suppressMessages(usethis::proj_set(temp_path))
      suppressMessages(usethis::use_directory(file.path("tests", "google_benchmark")))
      file.create(file.path("tests", "google_benchmark", "CMakeLists.txt"))

      #' @description Test that invalid benchmark names throw an informative format error.
      expect_error(
        FIMS:::use_google_benchmark_template(name = "Population_CatchNumbersAtAge"),
        regexp = "Expected format: \"FileName_ClassName_FunctionName\""
      )
    }
  )
})
